<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>VOID SIGNAL // 2026</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&family=Anton&family=Inter:wght@300;900&display=swap');

*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

:root {
  --void: #0a0a0a;
  --acid: #c8ff00;
  --blood: #ff1a5f;
  --ice: #00f0ff;
  --bone: #f0ece2;
  --rot: #b534f2;
  --smoke: #1a1a1a;
}

html { scroll-behavior: smooth; scrollbar-width: thin; scrollbar-color: var(--acid) var(--void); }

body {
  background: var(--void); color: var(--bone); font-family: 'Inter', sans-serif;
  overflow-x: hidden; cursor: crosshair;
}

::selection { background: var(--acid); color: var(--void); }

/* ═══ KEYFRAMES ═══ */
@keyframes gc {
  0%,100%{clip-path:inset(0 0 95% 0);transform:translate(-2px,2px)}
  10%{clip-path:inset(20% 0 60% 0);transform:translate(2px,-1px)}
  25%{clip-path:inset(50% 0 30% 0);transform:translate(-1px,3px)}
  40%{clip-path:inset(70% 0 5% 0);transform:translate(3px,0)}
  55%{clip-path:inset(40% 0 40% 0);transform:translate(1px,-2px)}
  70%{clip-path:inset(60% 0 20% 0);transform:translate(-2px,0)}
  85%{clip-path:inset(5% 0 70% 0);transform:translate(2px,2px)}
}
@keyframes gm {
  0%,100%{clip-path:inset(95% 0 0 0);transform:translate(2px,-2px)}
  15%{clip-path:inset(60% 0 20% 0);transform:translate(-3px,1px)}
  30%{clip-path:inset(80% 0 5% 0);transform:translate(1px,-3px)}
  45%{clip-path:inset(30% 0 50% 0);transform:translate(-2px,2px)}
  60%{clip-path:inset(50% 0 30% 0);transform:translate(3px,0)}
  75%{clip-path:inset(15% 0 70% 0);transform:translate(-1px,-2px)}
  90%{clip-path:inset(40% 0 40% 0);transform:translate(2px,1px)}
}
@keyframes flicker {
  0%,100%{opacity:1} 41%{opacity:1} 42%{opacity:0.7} 43%{opacity:1}
  45%{opacity:0.3} 46%{opacity:1} 51%{opacity:0.6} 52%{opacity:1}
  93%{opacity:0.5} 94%{opacity:1}
}
@keyframes scanline-move {
  0%{transform:translateY(-100%)} 100%{transform:translateY(100vh)}
}
@keyframes marquee {
  0%{transform:translateX(0)} 100%{transform:translateX(-50%)}
}
@keyframes rslow { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
@keyframes nshift {
  0%,100%{background-position:0 0} 25%{background-position:50% 50%}
  50%{background-position:-25% 75%} 75%{background-position:75% 25%}
}

/* ═══ OVERLAYS ═══ */
.scanline-overlay {
  position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:9999;
  background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,0.03) 2px,rgba(0,0,0,0.03) 4px);
}
.scanline-overlay::after {
  content:'';position:absolute;top:0;left:0;width:100%;height:8px;
  background:linear-gradient(to bottom,transparent,rgba(200,255,0,0.04),transparent);
  animation:scanline-move 4s linear infinite;
}
.noise-bg {
  position:fixed;top:-50%;left:-50%;width:200%;height:200%;z-index:-1;opacity:0.035;pointer-events:none;
  background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  animation:nshift 0.5s steps(10) infinite;
}

/* ═══ NAV ═══ */
nav { position:fixed;top:2rem;right:2rem;z-index:1000;mix-blend-mode:difference; }
nav ul { list-style:none;display:flex;gap:0; }
nav a {
  font-family:'Space Mono',monospace;font-size:0.7rem;letter-spacing:0.2em;text-transform:uppercase;
  color:var(--bone);text-decoration:none;padding:0.6rem 1.4rem;display:block;transition:all 0.3s;position:relative;
}
nav a::before { content:'//';margin-right:0.4rem;color:var(--acid);opacity:0;transition:opacity 0.2s; }
nav a:hover::before { opacity:1; }
nav a:hover { color:var(--acid);background:rgba(200,255,0,0.05); }

/* ═══ HERO ═══ */
.hero {
  min-height:100vh;display:grid;
  grid-template-columns:1fr 1fr 1fr;
  grid-template-rows:auto auto auto;
  position:relative;overflow:hidden;
}
.hero-title-block { grid-column:1/3;grid-row:1;padding:8vh 5vw 0 3vw;position:relative; }
.hero-date-stamp {
  font-family:'Space Mono',monospace;font-size:clamp(0.55rem,0.9vw,0.8rem);
  letter-spacing:0.5em;text-transform:uppercase;color:var(--acid);
  margin-bottom:1.5rem;display:inline-block;border-left:3px solid var(--acid);padding-left:1.2rem;
  animation:flicker 8s infinite;
}
.hero-title {
  font-family:'Anton',sans-serif;font-size:clamp(4rem,15vw,14rem);
  line-height:0.85;text-transform:uppercase;letter-spacing:-0.03em;
  color:var(--bone);position:relative;
}
.hero-title .glitch-layer { position:absolute;top:0;left:0;width:100%;height:100%; }
.hero-title .lc { color:var(--ice);animation:gc 3s infinite linear alternate-reverse;z-index:1; }
.hero-title .lm { color:var(--blood);animation:gm 2.5s infinite linear alternate-reverse;z-index:1; }
.hero-title .layer-main { z-index:2; }
.hero-subtitle {
  font-weight:300;font-size:clamp(0.85rem,1.8vw,1.3rem);letter-spacing:0.15em;text-transform:uppercase;
  color:rgba(240,236,226,0.35);margin-top:1.5rem;max-width:40ch;
}
.hero-visual { grid-column:3;grid-row:1/3;position:relative;overflow:hidden; }
.hero-visual::before {
  content:'';position:absolute;inset:0;
  background:linear-gradient(135deg,var(--acid) 0%,transparent 40%),linear-gradient(225deg,var(--blood) 0%,transparent 40%);
  opacity:0.25;z-index:2;
}
.hero-visual-inner {
  width:100%;height:100%;min-height:60vh;
  background:linear-gradient(45deg,var(--smoke) 25%,transparent 25%),
    linear-gradient(-45deg,var(--smoke) 25%,transparent 25%),
    linear-gradient(45deg,transparent 75%,var(--smoke) 75%),
    linear-gradient(-45deg,transparent 75%,var(--smoke) 75%);
  background-size:20px 20px;background-position:0 0,0 10px,10px -10px,-10px 0;
  opacity:0.5;display:flex;align-items:center;justify-content:center;
}
.hero-visual-symbol {
  font-size:12rem;font-family:'Anton',sans-serif;color:var(--void);opacity:0.15;animation:rslow 20s linear infinite;
}
.hero-info-side { grid-column:3;grid-row:3;padding:2rem 1rem;margin-top:-2vh; }
.hero-info-side .side-tag {
  writing-mode:vertical-rl;text-orientation:mixed;font-family:'Space Mono',monospace;font-size:0.6rem;
  letter-spacing:0.4em;text-transform:uppercase;color:rgba(200,255,0,0.3);padding-right:1rem;
  border-right:1px solid rgba(200,255,0,0.15);
}
.diagonal-divider {
  position:absolute;top:0;right:30%;width:2px;height:100%;
  background:linear-gradient(to bottom,transparent,var(--acid),var(--blood),transparent);
  transform:skewX(-12deg);opacity:0.3;z-index:3;
}
.diagonal-divider:nth-of-type(2) { right:32%;transform:skewX(-12deg) scaleX(0.5);opacity:0.15;background:linear-gradient(to bottom,transparent,var(--ice),transparent); }
.coord-block {
  position:absolute;bottom:3vh;left:5vw;font-family:'Space Mono',monospace;font-size:0.6rem;
  letter-spacing:0.15em;color:rgba(240,236,226,0.18);line-height:2;z-index:5;
}

/* ═══ MARQUEE ═══ */
.marquee-strip {
  background:var(--acid);color:var(--void);padding:0.8rem 0;overflow:hidden;white-space:nowrap;
  transform:rotate(-1.5deg) scale(1.03);margin:4rem -2vw;z-index:10;
  font-family:'Space Mono',monospace;font-weight:700;font-size:0.8rem;letter-spacing:0.1em;text-transform:uppercase;
}
.marquee-strip::before,.marquee-strip::after {
  content:'';position:absolute;top:0;width:15vw;height:100%;z-index:2;
}
.marquee-strip::before { left:0;background:linear-gradient(to right,var(--void),transparent); }
.marquee-strip::after { right:0;background:linear-gradient(to left,var(--void),transparent); }
.mc { display:inline-block;animation:marquee 20s linear infinite; }
.mc span { margin-right:3rem; }
.sep { color:var(--blood);font-size:1.2rem;margin:0 1rem; }

/* ═══ LINEUP ═══ */
.lineup-section { padding:12vh 5vw;position:relative; }
.section-label {
  font-family:'Space Mono',monospace;font-size:0.6rem;letter-spacing:0.5em;text-transform:uppercase;
  color:var(--acid);margin-bottom:4rem;display:flex;align-items:center;gap:1.5rem;
}
.section-label::before { content:'';width:40px;height:1px;background:var(--acid); }
.section-number {
  font-family:'Anton',sans-serif;font-size:clamp(3rem,8vw,7rem);line-height:1;color:transparent;
  -webkit-text-stroke:1px rgba(200,255,0,0.12);margin-bottom:2rem;text-transform:uppercase;
}
.lineup-grid { display:flex;flex-direction:column;gap:0; }
.artist-row {
  display:grid;grid-template-columns:120px 1fr auto;align-items:baseline;padding:3rem 0;
  border-bottom:1px solid rgba(240,236,226,0.06);position:relative;
  transition:all 0.4s cubic-bezier(0.23,1,0.32,1);cursor:default;
}
.artist-row:hover { padding-left:2rem;border-bottom-color:var(--acid); }
.artist-row.featured { grid-template-columns:120px 1fr;padding:5rem 0;border-bottom:none; }
.artist-row.featured::after {
  content:'';position:absolute;left:0;bottom:0;width:60px;height:4px;background:var(--blood);
}
.artist-row.main-headliner { grid-template-columns:100px 1fr auto;padding:6rem 0;border-bottom:none; }
.artist-row.main-headliner:hover { padding-left:3rem; }
.artist-time {
  font-family:'Space Mono',monospace;font-size:0.7rem;letter-spacing:0.2em;
  color:rgba(240,236,226,0.22);text-transform:uppercase;
}
.artist-name {
  font-family:'Anton',sans-serif;font-size:clamp(2rem,5vw,4.5rem);line-height:1;
  text-transform:uppercase;letter-spacing:-0.02em;transition:all 0.4s;
}
.artist-row:hover .artist-name { color:var(--acid);transform:translateX(0.5rem); }
.artist-row.main-headliner .artist-name {
  font-size:clamp(3rem,8vw,7rem);color:var(--bone);
  text-shadow:4px 0 var(--ice),-4px 0 var(--blood);animation:flicker 6s infinite;
}
.artist-genre {
  font-family:'Space Mono',monospace;font-size:0.55rem;letter-spacing:0.3em;text-transform:uppercase;
  color:rgba(200,255,0,0.3);padding:0.4rem 0.8rem;border:1px solid rgba(200,255,0,0.15);margin-left:2rem;
}
.ftags { display:flex;flex-wrap:wrap;gap:0.5rem;margin-top:1rem; }
.ftag {
  font-family:'Space Mono',monospace;font-size:0.5rem;letter-spacing:0.15em;text-transform:uppercase;
  color:var(--bone);background:rgba(200,255,0,0.04);border:1px solid rgba(200,255,0,0.1);padding:0.3rem 0.7rem;
}
.stagger-2 { margin-left:4vw; }
.stagger-3 { margin-left:-2vw; }
.stagger-4 { margin-left:6vw; }
.stagger-5 { margin-left:1vw; }
.stagger-6 { margin-left:-4vw; }

/* ═══ LOCATION ═══ */
.location-section { position:relative;margin:0 -2vw;padding:10vh 5vw;overflow:hidden; }
.location-bg-block {
  position:absolute;top:0;left:0;width:65%;height:100%;background:var(--smoke);
  clip-path:polygon(0 0,100% 0,85% 100%,0 100%);
}
.location-content { position:relative;z-index:2;display:grid;grid-template-columns:1fr 1fr;gap:4rem; }
.location-title {
  font-family:'Anton',sans-serif;font-size:clamp(3rem,7vw,6rem);text-transform:uppercase;line-height:0.95;letter-spacing:-0.03em;
}
.location-title .accent { color:var(--acid); }
.location-details { display:flex;flex-direction:column;gap:3rem;margin-top:2rem; }
.detail-block { border-left:2px solid var(--blood);padding-left:1.5rem; }
.detail-label {
  font-family:'Space Mono',monospace;font-size:0.6rem;letter-spacing:0.4em;text-transform:uppercase;
  color:rgba(240,236,226,0.25);margin-bottom:0.6rem;
}
.detail-value { font-weight:900;font-size:clamp(1rem,2vw,1.4rem);text-transform:uppercase;letter-spacing:0.05em; }
.detail-value.accent { color:var(--ice); }
.detail-value.blood { color:var(--blood); }
.coords-float {
  font-family:'Space Mono',monospace;font-size:0.6rem;color:rgba(200,255,0,0.12);writing-mode:vertical-rl;
  position:absolute;right:5vw;top:50%;transform:translateY(-50%) rotate(180deg);letter-spacing:0.3em;z-index:1;
}

/* ═══ INFO CARDS ═══ */
.info-section { padding:12vh 5vw; }
.info-grid { display:flex;flex-direction:column;gap:0; }
.info-card {
  position:relative;padding:4rem 3rem;border:1px solid rgba(240,236,226,0.06);
  transition:all 0.5s cubic-bezier(0.23,1,0.32,1);overflow:hidden;
}
.info-card::before {
  content:'';position:absolute;top:0;left:0;width:4px;height:0;
  transition:height 0.5s cubic-bezier(0.23,1,0.32,1);
}
.info-card:nth-child(1)::before { background:var(--acid); }
.info-card:nth-child(2)::before { background:var(--blood); }
.info-card:nth-child(3)::before { background:var(--ice); }
.info-card:hover::before { height:100%; }
.info-card:hover { transform:translateX(1rem) skewX(-1deg);border-color:rgba(240,236,226,0.12);background:rgba(200,255,0,0.01); }
.info-card:nth-child(2) { margin-left:8vw; }
.info-card:nth-child(3) { margin-left:-4vw; }
.ic-num {
  font-family:'Anton',sans-serif;font-size:5rem;line-height:1;color:transparent;
  -webkit-text-stroke:1px rgba(240,236,226,0.07);position:absolute;top:1rem;right:2rem;
}
.ic-icon { font-size:1.5rem;margin-bottom:1.5rem;display:inline-block; }
.ic-title { font-family:'Anton',sans-serif;font-size:clamp(1.5rem,3vw,2.5rem);text-transform:uppercase;letter-spacing:-0.01em;margin-bottom:1rem; }
.ic-text { font-weight:300;font-size:0.9rem;line-height:1.8;color:rgba(240,236,226,0.45);max-width:35ch; }

/* ═══ CTA ═══ */
.cta-section {
  position:relative;padding:15vh 5vw;display:flex;flex-direction:column;align-items:flex-start;overflow:hidden;
}
.cta-section::before {
  content:'';position:absolute;top:0;right:0;width:50%;height:100%;background:var(--blood);
  clip-path:polygon(30% 0,100% 0,100% 100%,0 100%);opacity:0.07;
}
.cta-big {
  font-family:'Anton',sans-serif;font-size:clamp(4rem,12vw,12rem);line-height:0.9;
  text-transform:uppercase;letter-spacing:-0.04em;position:relative;z-index:2;
}
.cta-big .hl { color:var(--acid);display:inline-block;position:relative; }
.cta-big .hl::after {
  content:'';position:absolute;bottom:0.1em;left:0;width:100%;height:0.15em;background:var(--acid);
  transform:scaleX(0);transform-origin:right;transition:transform 0.6s cubic-bezier(0.23,1,0.32,1);
}
.cta-big .hl:hover::after { transform:scaleX(1);transform-origin:left; }
.cta-sub {
  font-family:'Space Mono',monospace;font-size:0.7rem;letter-spacing:0.3em;text-transform:uppercase;
  color:rgba(240,236,226,0.25);margin-top:3rem;position:relative;z-index:2;margin-left:0.1em;
}

/* ═══ BUTTON ═══ */
.cta-btn {
  display:inline-flex;align-items:center;gap:1.5rem;margin-top:4rem;position:relative;z-index:2;
  font-family:'Space Mono',monospace;font-size:0.8rem;letter-spacing:0.2em;text-transform:uppercase;
  text-decoration:none;color:var(--void);background:var(--acid);padding:1.2rem 3rem;
  border:none;cursor:pointer;transition:all 0.4s cubic-bezier(0.23,1,0.32,1);
  clip-path:polygon(0 0,calc(100% - 1rem) 0,100% 1rem,100% 100%,1rem 100%,0 calc(100% - 1rem));
}
.cta-btn:hover { background:var(--bone);transform:translateX(0.5rem) translateY(-0.2rem);box-shadow:8px 8px 0 var(--blood); }
.cta-btn .arrow { transition:transform 0.3s; }
.cta-btn:hover .arrow { transform:translateX(0.5rem); }
.cta-corner {
  font-family:'Space Mono',monospace;font-size:0.55rem;letter-spacing:0.2em;
  color:rgba(240,236,226,0.15);margin-top:2rem;position:relative;z-index:2;
}

/* ═══ FOOTER ═══ */
.footer {
  padding:6vh 5vw;border-top:1px solid rgba(240,236,226,0.06);
  display:flex;justify-content:space-between;align-items:flex-end;flex-wrap:wrap;gap:2rem;
}
.footer-brand { font-family:'Anton',sans-serif;font-size:1.2rem;text-transform:uppercase;letter-spacing:0.05em; }
.footer-links { display:flex;gap:2rem; }
.footer-links a {
  font-family:'Space Mono',monospace;font-size:0.6rem;letter-spacing:0.2em;text-transform:uppercase;
  color:rgba(240,236,226,0.3);text-decoration:none;transition:color 0.3s;
}
.footer-links a:hover { color:var(--acid); }
.footer-copy {
  font-family:'Space Mono',monospace;font-size:0.55rem;letter-spacing:0.1em;color:rgba(240,236,226,0.15);margin-top:3rem;
}

/* ═══ MOBILE ═══ */
@media (max-width:768px) {
  nav{top:1rem;right:1rem;}
  .hero{grid-template-columns:1fr;}
  .hero-title-block{grid-column:1;grid-row:1;}
  .hero-visual{grid-column:1;grid-row:2;min-height:30vh;}
  .hero-info-side,.diagonal-divider,.coord-block,.coords-float{display:none;}
  .marquee-strip{margin:2rem 0;transform:rotate(-1deg) scale(1.02);}
  .location-content{grid-template-columns:1fr;}
  .location-bg-block{display:none;}
  .artist-row{grid-template-columns:80px 1fr!important;}
  .artist-row .artist-genre{display:none;}
  .artist-row,.artist-row.stagger-2,.artist-row.stagger-3,.artist-row.stagger-4,.artist-row.stagger-5,.artist-row.stagger-6{margin-left:0!important;}
  .info-card:nth-child(2),.info-card:nth-child(3){margin-left:0;}
  .info-card{padding:3rem 2rem;}
  .cta-big{font-size:clamp(3rem,15vw,6rem);}
  .footer{flex-direction:column;align-items:flex-start;}
}
</style>
</head>
