@import url('https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&family=Anton&family=Inter:wght@300;400;900&display=swap');

/* ════════════════════════════════════════
   CUSTOM PROPERTIES
   ════════════════════════════════════════ */
:root {
  --void:       #0a0a0a;
  --black:      #000000;
  --smoke:      #1a1a1a;
  --smoke-light:#2a2a2a;
  --bone:       #f0ece2;
  --bone-muted: rgba(240, 236, 226, 0.5);
  --bone-faint: rgba(240, 236, 226, 0.15);
  --acid:       #c8ff00;
  --blood:      #ff1a5f;
  --ice:        #00f0ff;
  --rot:        #b534f2;

  --ease-out-expo: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-in-out:   cubic-bezier(0.65, 0, 0.35, 1);
}

/* ════════════════════════════════════════
   RESET & BASE
   ════════════════════════════════════════ */
*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scrollbar-width: thin;
  scrollbar-color: var(--acid) var(--void);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  background: var(--void);
  color: var(--bone);
  font-family: 'Inter', system-ui, sans-serif;
  line-height: 1.5;
  overflow-x: hidden;
  cursor: crosshair;
}

::selection {
  background: var(--acid);
  color: var(--black);
}

img { max-width: none; display: block; }
a { color: inherit; text-decoration: none; }
ul { list-style: none; }

/* ════════════════════════════════════════
   OVERLAY EFFECTS
   ════════════════════════════════════════ */
.scanlines {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 10000;
  background: repeating-linear-gradient(
    to bottom,
    transparent 0px,
    transparent 3px,
    rgba(0, 0, 0, 0.04) 3px,
    rgba(0, 0, 0, 0.04) 6px
  );
}

.scanlines::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(
    to bottom,
    transparent 0%,
    rgba(200, 255, 0, 0.015) 50%,
    transparent 100%
  );
  animation: scanline-sweep 6s ease-in-out infinite;
}

@keyframes scanline-sweep {
  0%   { transform: translateY(-100%); }
  100% { transform: translateY(100%); }
}

.noise {
  position: fixed;
  inset: -50%;
  width: 200%;
  height: 200%;
  z-index: -1;
  opacity: 0.025;
  pointer-events: none;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 512 512' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.75' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  background-size: 256px 256px;
  animation: noise-drift 0.4s steps(6) infinite;
}

@keyframes noise-drift {
  0%   { background-position: 0 0; }
  20%  { background-position: 80px 60px; }
  40%  { background-position: -40px 100px; }
  60%  { background-position: 100px -20px; }
  80%  { background-position: -60px 40px; }
  100% { background-position: 0 0; }
}

/* ════════════════════════════════════════
   GLITCH KEYFRAMES
   ════════════════════════════════════════ */
@keyframes glitch-cyan {
  0%, 100%  { clip-path: inset(0 0 95% 0); transform: translate(-3px, 2px); }
  10%       { clip-path: inset(15% 0 60% 0); transform: translate(3px, -2px); }
  25%       { clip-path: inset(50% 0 30% 0); transform: translate(-2px, 4px); }
  40%       { clip-path: inset(70% 0 5% 0); transform: translate(4px, 0); }
  55%       { clip-path: inset(40% 0 40% 0); transform: translate(1px, -3px); }
  70%       { clip-path: inset(55% 0 20% 0); transform: translate(-3px, 0); }
  85%       { clip-path: inset(8% 0 72% 0); transform: translate(2px, 2px); }
}

@keyframes glitch-magenta {
  0%, 100%  { clip-path: inset(95% 0 0 0); transform: translate(3px, -2px); }
  15%       { clip-path: inset(60% 0 20% 0); transform: translate(-4px, 1px); }
  30%       { clip-path: inset(80% 0 5% 0); transform: translate(1px, -4px); }
  45%       { clip-path: inset(30% 0 50% 0); transform: translate(-3px, 3px); }
  60%       { clip-path: inset(50% 0 30% 0); transform: translate(4px, 0); }
  75%       { clip-path: inset(15% 0 70% 0); transform: translate(-1px, -3px); }
  90%       { clip-path: inset(40% 0 40% 0); transform: translate(3px, 2px); }
}

@keyframes flicker {
  0%, 100%   { opacity: 1; }
  41%        { opacity: 1; }
  42%        { opacity: 0.6; }
  43%        { opacity: 1; }
  45%        { opacity: 0.3; }
  46%        { opacity: 1; }
  51%        { opacity: 0.7; }
  52%        { opacity: 1; }
  93%        { opacity: 0.5; }
  94%        { opacity: 1; }
}

@keyframes marquee-scroll {
  0%   { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

@keyframes rotate-slow {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}

@keyframes pulse-border {
  0%, 100% { border-color: var(--acid); }
  33%      { border-color: var(--blood); }
  66%      { border-color: var(--ice); }
}

@keyframes reveal-up {
  0%   { opacity: 0; transform: translateY(40px); }
  100% { opacity: 1; transform: translateY(0); }
}

.reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: opacity 0.8s var(--ease-out-expo), transform 0.8s var(--ease-out-expo);
}
.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

/* ════════════════════════════════════════
   NAVIGATION
   ════════════════════════════════════════ */
.nav {
  position: fixed;
  top: 2rem;
  right: 2rem;
  z-index: 1000;
  mix-blend-mode: difference;
  display: flex;
  align-items: center;
  gap: 2.5rem;
}

.nav__logotype {
  font-family: 'Anton', sans-serif;
  font-size: 0.9rem;
  letter-spacing: 0.15em;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.nav__dot {
  display: inline-block;
  width: 6px;
  height: 6px;
  background: var(--acid);
  animation: flicker 5s infinite;
}

.nav__links {
  display: flex;
  gap: 0;
}

.nav__links a {
  font-family: 'Space Mono', monospace;
  font-size: 0.65rem;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  padding: 0.5rem 1rem;
  transition: all 0.3s ease;
  position: relative;
}

.nav__links a::before {
  content: '//';
  margin-right: 0.3rem;
  color: var(--acid);
  opacity: 0;
  transition: opacity 0.2s;
}

.nav__links a:hover::before {
  opacity: 1;
}

.nav__links a:hover {
  color: var(--acid);
  background: rgba(200, 255, 0, 0.04);
}

.nav__cta {
  border: 1px solid rgba(200, 255, 0, 0.3);
  padding: 0.5rem 1.2rem !important;
}

.nav__cta:hover {
  background: var(--acid) !important;
  color: var(--void) !important;
}

.nav__cta:hover::before {
  color: var(--void);
}

@media (max-width: 600px) {
  .nav {
    top: 1rem;
    right: 1rem;
    left: 1rem;
    justify-content: space-between;
  }
  .nav__links a {
    padding: 0.5rem 0.6rem !important;
    font-size: 0.55rem;
  }
}

/* ════════════════════════════════════════
   HERO SECTION
   ════════════════════════════════════════ */
.hero {
  min-height: 100vh;
  display: grid;
  grid-template-columns: 1.1fr 0.6fr 0.8fr;
  grid-template-rows: auto 1fr auto;
  position: relative;
  overflow: hidden;
  padding-top: 6vh;
}

/* Background pattern --- checkerboard hint */
.hero__bg-pattern {
  position: absolute;
  inset: 0;
  background:
    linear-gradient(45deg, var(--smoke) 25%, transparent 25%) -10px 0,
    linear-gradient(-45deg, var(--smoke) 25%, transparent 25%) -10px 0,
    linear-gradient(45deg, transparent 75%, var(--smoke) 75%),
    linear-gradient(-45deg, transparent 75%, var(--smoke) 75%);
  background-size: 20px 20px;
  background-position: 0 0, 0 10px, 10px -10px, -10px 0;
  opacity: 0.06;
  z-index: 0;
}

/* ── Text area ── */
.hero__text {
  grid-column: 1 / 2;
  grid-row: 1 / 3;
  padding: 6vh 0 0 4vw;
  position: relative;
  z-index: 2;
}

/* Meta strip above title */
.hero__meta {
  font-family: 'Space Mono', monospace;
  font-size: clamp(0.6rem, 0.85vw, 0.85rem);
  letter-spacing: 0.45em;
  text-transform: uppercase;
  color: var(--acid);
  margin-bottom: 2rem;
  display: flex;
  align-items: center;
  gap: 0.4rem;
  animation: flicker 10s infinite;
}

.meta-sep {
  opacity: 0.4;
}

/* ── Title with chromatic glitch ── */
.hero__title {
  font-family: 'Anton', sans-serif;
  font-size: clamp(5rem, 16vw, 16rem);
  line-height: 0.82;
  text-transform: uppercase;
  letter-spacing: -0.04em;
  color: var(--bone);
  position: relative;
  margin-left: -0.05em;
}

.hero__word {
  display: inline-block;
  position: relative;
}

.hero__word.title-main {
  position: relative;
  z-index: 2;
}

/* Glitch overlay layers --- cyan and magenta */
.hero__word[data-layer--cyan],
.hero__word[data-layer--magenta] {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  z-index: 1;
}

.hero__word[data-layer--cyan] {
  color: var(--ice);
  animation: glitch-cyan 3.5s infinite linear alternate-reverse;
}

.hero__word[data-layer--magenta] {
  color: var(--blood);
  animation: glitch-magenta 3s infinite linear alternate-reverse;
}

/* Tagline under title */
.hero__tagline {
  font-weight: 300;
  font-size: clamp(0.9rem, 1.5vw, 1.3rem);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--bone-muted);
  margin-top: 2rem;
  max-width: 38ch;
  line-height: 1.6;
}

/* ── Geometric visuals on right ── */
.hero__visual {
  grid-column: 3;
  grid-row: 1 / 3;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 2;
}

/* Diamond shape -- pure CSS geometric form */
.hero__shape {
  position: absolute;
}

.shape--diamond {
  width: clamp(180px, 18vw, 350px);
  height: clamp(180px, 18vw, 350px);
  background: var(--acid);
  transform: rotate(45deg);
  animation: rotate-slow 30s linear infinite;
  opacity: 0.12;
}

.shape--ring {
  width: clamp(220px, 22vw, 420px);
  height: clamp(220px, 22vw, 420px);
  border: 2px solid var(--blood);
  border-radius: 50%;
  animation: rotate-slow 20s linear infinite reverse;
  opacity: 0.08;
}

/* ── Corner coords ── */
.hero__coords {
  grid-column: 1;
  grid-row: 3;
  position: relative;
  padding: 0 4vw;
  font-family: 'Space Mono', monospace;
  font-size: 0.6rem;
  letter-spacing: 0.15em;
  color: rgba(240, 236, 226, 0.18);
  line-height: 2.2;
  z-index: 3;
}

.coords--classified {
  margin-top: 0.5rem;
  text-transform: uppercase;
  color: var(--acid);
  opacity: 0.3;
  font-size: 0.5rem;
  letter-spacing: 0.3em;
}

/* ── Vertical side tag ── */
.hero__side-tag {
  grid-column: 3;
  grid-row: 3;
  writing-mode: vertical-rl;
  text-orientation: mixed;
  font-family: 'Space Mono', monospace;
  font-size: 0.55rem;
  letter-spacing: 0.4em;
  text-transform: uppercase;
  color: rgba(200, 255, 0, 0.25);
  padding: 3rem 0 0 1rem;
  margin-top: 1vh;
  z-index: 3;
}

/* ── Diagonal structural lines ── */
.hero__line {
  position: absolute;
  top: 0;
  width: 2px;
  height: 100%;
  z-index: 3;
  pointer-events: none;
}

.line--1 {
  right: 32%;
  background: linear-gradient(to bottom, transparent, var(--acid), var(--blood), transparent);
  transform: skewX(-10deg);
  opacity: 0.25;
  transition: transform 0.3s ease-out;
}

.line--2 {
  right: 34.5%;
  width: 1px;
  background: linear-gradient(to bottom, transparent, var(--ice), transparent);
  transform: skewX(-10deg);
  opacity: 0.12;
  transition: transform 0.3s ease-out;
}

@media (max-width: 900px) {
  .hero {
    grid-template-columns: 1fr;
    grid-template-rows: auto auto auto;
    padding-top: 10vh;
  }
  .hero__text {
    grid-column: 1;
    grid-row: 1;
    padding: 2rem 5vw 0;
  }
  .hero__visual {
    grid-column: 1;
    grid-row: 2;
    min-height: 25vh;
  }
  .hero__coords,
  .hero__side-tag {
    display: none;
  }
  .hero__line { display: none; }
}

/* ════════════════════════════════════════
   MARQUEE STRIP
   ════════════════════════════════════════ */
.marquee {
  background: var(--acid);
  color: var(--black);
  padding: 0.9rem 0;
  overflow: hidden;
  white-space: nowrap;
  position: relative;
  transform: rotate(-1.8deg) scale(1.025);
  margin: 5rem -2vw;
  z-index: 10;
  font-family: 'Space Mono', monospace;
  font-weight: 700;
  font-size: clamp(0.7rem, 1vw, 0.9rem);
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

/* Fade edges */
.marquee::before,
.marquee::after {
  content: '';
  position: absolute;
  top: 0;
  width: 12vw;
  height: 100%;
  z-index: 2;
  pointer-events: none;
}
.marquee::before {
  left: 0;
  background: linear-gradient(to right, var(--void), transparent);
}
.marquee::after {
  right: 0;
  background: linear-gradient(to left, var(--void), transparent);
}

.marquee__inner {
  display: inline-flex;
  animation: marquee-scroll 25s linear infinite;
}

.sep {
  margin: 0 1.5rem;
  font-size: 1.1rem;
  opacity: 0.7;
}

/* Red variant for rules section */
.marquee--rules {
  background: var(--blood);
  margin: 0 -2vw;
  transform: rotate(1.5deg) scale(1.02);
}

.marquee__inner--reverse {
  animation-direction: reverse;
}

@media (max-width: 600px) {
  .marquee,
  .marquee--rules {
    margin: 2.5rem 0;
    transform: rotate(-1deg) scale(1.01);
  }
}

/* ════════════════════════════════════════
   LINEUP
   ════════════════════════════════════════ */
.lineup {
  padding: 14vh 4vw;
  position: relative;
}

/* ── Section Header ── */
.section-header {
  display: flex;
  align-items: baseline;
  gap: 1.5rem;
  margin-bottom: 5rem;
}

.section-number {
  font-family: 'Anton', sans-serif;
  font-size: clamp(3rem, 9vw, 9rem);
  line-height: 0.85;
  color: transparent;
  -webkit-text-stroke: 1.2px rgba(200, 255, 0, 0.1);
  text-transform: uppercase;
  user-select: none;
}

.section-title {
  font-family: 'Space Mono', monospace;
  font-size: clamp(0.7rem, 1vw, 0.9rem);
  letter-spacing: 0.5em;
  text-transform: uppercase;
  color: var(--acid);
  position: relative;
}

.section-title::before {
  content: '';
  display: inline-block;
  width: 50px;
  height: 1px;
  background: var(--acid);
  margin-right: 1.5rem;
  vertical-align: middle;
}

/* ── Artist Rows ── */
.lineup__list {
  display: flex;
  flex-direction: column;
  gap: 0;
}

.artist-row {
  display: grid;
  grid-template-columns: 100px 1fr auto;
  align-items: center;
  padding: 3rem 0;
  border-bottom: 1px solid rgba(240, 236, 226, 0.05);
  position: relative;
  transition: all 0.5s var(--ease-out-expo);
  cursor: default;
}

.artist-row:hover {
  padding-left: 2.5rem;
  border-bottom-color: var(--acid);
}

/* Stagger offsets -- core asymmetry */
.stagger--right        { margin-left: 4vw; }
.stagger--left         { margin-left: -2.5vw; }
.stagger--far-right    { margin-left: 7vw; }
.stagger--mid-left     { margin-left: 1.5vw; }
.stagger--extreme-right{ margin-left: -5vw; }
.stagger--mid-right    { margin-left: 5.5vw; }

/* ── Time badge ── */
.artist-row__time {
  font-family: 'Space Mono', monospace;
  font-size: 0.65rem;
  letter-spacing: 0.2em;
  color: rgba(240, 236, 226, 0.2);
  text-transform: uppercase;
  padding-top: 0.2rem;
}

/* ── Artist content ── */
.artist-row__name {
  font-family: 'Anton', sans-serif;
  font-size: clamp(2.2rem, 5vw, 5rem);
  line-height: 1;
  text-transform: uppercase;
  letter-spacing: -0.02em;
  transition: all 0.4s var(--ease-out-expo);
  color: var(--bone);
}

.artist-row:hover .artist-row__name {
  color: var(--acid);
  transform: translateX(0.6rem);
}

/* Headliner size override */
.artist-row--headline .artist-row__name {
  font-size: clamp(3.5rem, 9vw, 8.5rem);
  color: var(--bone);
  text-shadow: 5px 0 var(--ice), -5px 0 var(--blood);
  animation: flicker 7s infinite;
}

.artist-row--headline:hover {
  padding-left: 3.5rem;
}

/* Genre tag */
.artist-row__genre {
  font-family: 'Space Mono', monospace;
  font-size: 0.55rem;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: rgba(200, 255, 0, 0.25);
  padding: 0.35rem 0.75rem;
  border: 1px solid rgba(200, 255, 0, 0.12);
  margin-top: 0.5rem;
  display: inline-block;
}

/* Tags row for featured artists */
.artist-row__tags {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  margin-top: 0.8rem;
}

.tag {
  font-family: 'Space Mono', monospace;
  font-size: 0.5rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--bone);
  background: rgba(200, 255, 0, 0.04);
  border: 1px solid rgba(200, 255, 0, 0.1);
  padding: 0.3rem 0.6rem;
}

/* Featured artist styling */
.artist-row--featured {
  padding: 5.5rem 0;
  border-bottom: none;
}

.artist-row--featured::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: 0;
  width: 70px;
  height: 4px;
  background: var(--blood);
}

.artist-row--featured:hover {
  border-bottom-color: var(--acid);
}

@media (max-width: 768px) {
  .lineup { padding: 8vh 5vw; }
  .section-number { font-size: 3rem; }
  .section-title { font-size: 0.6rem; }
  .section-title::before { width: 30px; margin-right: 1rem; }
  .artist-row {
    grid-template-columns: 70px 1fr;
    padding: 2rem 0;
  }
  .artist-row > :nth-child(3) { display: none; }
  .artist-row:hover { padding-left: 1.5rem; }
  .stagger--right,
  .stagger--left,
  .stagger--far-right,
  .stagger--mid-left,
  .stagger--extreme-right,
  .stagger--mid-right {
    margin-left: 0 !important;
  }
  .artist-row__genre { display: none; }
}

/* ════════════════════════════════════════
   LOCATION
   ════════════════════════════════════════ */
.location {
  position: relative;
  margin: 0 -2vw;
  padding: 14vh 4vw;
  overflow: hidden;
}

/* Color block clipped into polygon */
.location__color-block {
  position: absolute;
  top: 0;
  left: 0;
  width: 60%;
  height: 100%;
  background: var(--smoke);
  clip-path: polygon(0 0, 100% 0, 82% 100%, 0% 100%);
  z-index: 0;
}

.location__grid {
  position: relative;
  z-index: 2;
  display: grid;
  grid-template-columns: 0.8fr 1.2fr;
  gap: 6rem;
  align-items: start;
}

.location__heading {
  font-family: 'Anton', sans-serif;
  font-size: clamp(3rem, 7vw, 6.5rem);
  text-transform: uppercase;
  line-height: 0.95;
  letter-spacing: -0.03em;
}

.location__header {
  margin-bottom: 3rem;
}

/* Details list */
.details-list {
  display: flex;
  flex-direction: column;
  gap: 3rem;
}

.detail-label {
  font-family: 'Space Mono', monospace;
  font-size: 0.6rem;
  letter-spacing: 0.4em;
  text-transform: uppercase;
  color: rgba(240, 236, 226, 0.25);
  margin-bottom: 0.5rem;
  padding-left: 1.5rem;
  position: relative;
}

.detail-label::before {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 8px;
  height: 1px;
  background: currentColor;
  opacity: 0.5;
}

.detail-value {
  font-weight: 900;
  font-size: clamp(1rem, 2vw, 1.5rem);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  line-height: 1.4;
  padding-left: 1.5rem;
  border-left: 3px solid var(--blood);
}

.detail--ice  { color: var(--ice); }
.detail--blood { color: var(--blood); }
.detail--mono  {
  font-family: 'Space Mono', monospace;
  font-size: 0.75rem !important;
  font-weight: 400 !important;
  color: var(--bone-muted) !important;
  border-left-color: var(--acid) !important;
  letter-spacing: 0.1em;
}

/* Floating vertical coordinate */
.float-coords {
  font-family: 'Space Mono', monospace;
  font-size: 0.55rem;
  color: rgba(200, 255, 0, 0.1);
  writing-mode: vertical-rl;
  position: absolute;
  right: 4vw;
  top: 50%;
  transform: translateY(-50%) rotate(180deg);
  letter-spacing: 0.35em;
  z-index: 1;
}

@media (max-width: 768px) {
  .location__grid {
    grid-template-columns: 1fr;
    gap: 3rem;
  }
  .location__color-block { width: 100%; clip-path: none; opacity: 0.5; }
  .float-coords { display: none; }
  .detail-label { padding-left: 0; }
  .detail-label::before { display: none; }
  .detail-value { padding-left: 0; }
}

/* ════════════════════════════════════════
